class Produto:
    def __init__(self, nome, preco):
        self.nome  = nome
        self.preco = preco

def mais_baratos(produtos, limite):
    return sorted([p.nome for p in produtos if p.preco <= limite])

produtos = [Produto('camiseta',50), Produto('tenis',200), Produto('meia',15), Produto('boné',45)]
result = mais_baratos(produtos, 50)
for nome in result:
    print(nome)
